import java.util.*

val MOD = 1_000_000_007L

fun solve(points: Array<Array<Long>>): Long {
    val yToXs = mutableMapOf<Long, MutableList<Long>>()
    for ((x, y) in points) {
        yToXs.getOrPut(y) { mutableListOf() }.add(x)
    }

    // Sort the x-coordinates for each y
    for ((_, xs) in yToXs) {
        xs.sort()
    }

    val ys = yToXs.keys.sorted()
    var res = 0L

    // Precompute the count of pairs for each y
    val pairCounts = mutableMapOf<Long, Long>()
    for (y in ys) {
        val xs = yToXs[y]!!
        val n = xs.size
        if (n >= 2) {
            pairCounts[y] = n.toLong() * (n - 1) / 2
        }
    }

    // Iterate all possible pairs of y-coordinates
    for (i in ys.indices) {
        val y1 = ys[i]
        val cnt1 = pairCounts[y1] ?: continue
        for (j in i + 1 until ys.size) {
            val y2 = ys[j]
            val cnt2 = pairCounts[y2] ?: continue
            res += cnt1 * cnt2
            res %= MOD
        }
    }

    return res
}
